     1вҶ’/**
     2вҶ’ * SwapPuzzle - Canvas-based tile swap puzzle.
     3вҶ’ * Tiles are shuffled via Fisher-Yates and swapped by drag-and-drop.
     4вҶ’ * No dependency on input layer.
     5вҶ’ */
     6вҶ’const SwapPuzzle = {
     7вҶ’  /**
     8вҶ’   * Generate shuffled puzzle tiles.
     9вҶ’   * @param {number} cols
    10вҶ’   * @param {number} rows
    11вҶ’   * @returns {Array} Array of tile objects { id, origX, origY }
    12вҶ’   */
    13вҶ’  generate(cols, rows) {
    14вҶ’    const tiles = [];
    15вҶ’    for (let y = 0; y < rows; y++) {
    16вҶ’      for (let x = 0; x < cols; x++) {
    17вҶ’        tiles.push({ id: y * cols + x, origX: x, origY: y });
    18вҶ’      }
    19вҶ’    }
    20вҶ’    // Fisher-Yates shuffle
    21вҶ’    for (let i = tiles.length - 1; i > 0; i--) {
    22вҶ’      const j = Math.floor(Math.random() * (i + 1));
    23вҶ’      [tiles[i], tiles[j]] = [tiles[j], tiles[i]];
    24вҶ’    }
    25вҶ’    return tiles;
    26вҶ’  },
    27вҶ’
    28вҶ’  /**
    29вҶ’   * Check if puzzle is solved (every tile at its original index).
    30вҶ’   * @param {Array} tiles
    31вҶ’   * @returns {boolean}
    32вҶ’   */
    33вҶ’  isSolved(tiles) {
    34вҶ’    return tiles.every((tile, index) => tile.id === index);
    35вҶ’  },
    36вҶ’
    37вҶ’  /**
    38вҶ’   * Render the puzzle board.
    39вҶ’   * @param {CanvasRenderingContext2D} ctx
    40вҶ’   * @param {HTMLCanvasElement} image - Source image canvas
    41вҶ’   * @param {Array} tiles - Current tile arrangement
    42вҶ’   * @param {number} cols
    43вҶ’   * @param {number} rows
    44вҶ’   * @param {number} width - Board pixel width
    45вҶ’   * @param {number} height - Board pixel height
    46вҶ’   * @param {object|null} drag - { index, x, y } where x,y are relative to board
    47вҶ’   * @param {number|null} hoverIdx - Tile index under cursor
    48вҶ’   */
    49вҶ’  render(ctx, image, tiles, cols, rows, width, height, drag, hoverIdx) {
    50вҶ’    const tileW = width / cols;
    51вҶ’    const tileH = height / rows;
    52вҶ’    const srcTileW = image.width / cols;
    53вҶ’    const srcTileH = image.height / rows;
    54вҶ’
    55вҶ’    // Background
    56вҶ’    ctx.fillStyle = '#111';
    57вҶ’    ctx.fillRect(0, 0, width, height);
    58вҶ’
    59вҶ’    // Draw grid tiles
    60вҶ’    tiles.forEach((tile, i) => {
    61вҶ’      const dx = (i % cols) * tileW;
    62вҶ’      const dy = Math.floor(i / cols) * tileH;
    63вҶ’      const sx = tile.origX * srcTileW;
    64вҶ’      const sy = tile.origY * srcTileH;
    65вҶ’
    66вҶ’      if (drag && drag.index === i) {
    67вҶ’        // Empty slot where dragged tile was
    68вҶ’        ctx.fillStyle = '#222';
    69вҶ’        ctx.fillRect(dx, dy, tileW, tileH);
    70вҶ’        ctx.strokeStyle = '#333';
    71вҶ’        ctx.strokeRect(dx, dy, tileW, tileH);
    72вҶ’      } else if (drag && hoverIdx === i) {
    73вҶ’        // Potential swap target - dimmed with green tint
    74вҶ’        ctx.save();
    75вҶ’        ctx.globalAlpha = 0.5;
    76вҶ’        ctx.drawImage(image, sx, sy, srcTileW, srcTileH, dx, dy, tileW, tileH);
    77вҶ’        ctx.fillStyle = 'rgba(204, 255, 0, 0.2)';
    78вҶ’        ctx.fillRect(dx, dy, tileW, tileH);
    79вҶ’        ctx.strokeStyle = '#ccff00';
    80вҶ’        ctx.lineWidth = 2;
    81вҶ’        ctx.strokeRect(dx, dy, tileW, tileH);
    82вҶ’        ctx.restore();
    83вҶ’      } else {
    84вҶ’        // Normal tile
    85вҶ’        ctx.drawImage(image, sx, sy, srcTileW, srcTileH, dx, dy, tileW, tileH);
    86вҶ’        ctx.strokeStyle = '#ffffff';
    87вҶ’        ctx.lineWidth = 1;
    88вҶ’        ctx.strokeRect(dx, dy, tileW, tileH);
    89вҶ’      }
    90вҶ’    });
    91вҶ’
    92вҶ’    // Draw dragged tile on top (slightly larger, with shadow)
    93вҶ’    if (drag) {
    94вҶ’      const tile = tiles[drag.index];
    95вҶ’      const sx = tile.origX * srcTileW;
    96вҶ’      const sy = tile.origY * srcTileH;
    97вҶ’      const dragW = tileW * 1.1;
    98вҶ’      const dragH = tileH * 1.1;
    99вҶ’      const ddx = drag.x - dragW / 2;
   100вҶ’      const ddy = drag.y - dragH / 2;
   101вҶ’
   102вҶ’      ctx.save();
   103вҶ’      ctx.shadowColor = 'rgba(0,0,0,0.5)';
   104вҶ’      ctx.shadowBlur = 15;
   105вҶ’      ctx.shadowOffsetY = 10;
   106вҶ’      ctx.drawImage(image, sx, sy, srcTileW, srcTileH, ddx, ddy, dragW, dragH);
   107вҶ’      ctx.strokeStyle = '#ccff00';
   108вҶ’      ctx.lineWidth = 2;
   109вҶ’      ctx.strokeRect(ddx, ddy, dragW, dragH);
   110вҶ’      ctx.restore();
   111вҶ’    }
   112вҶ’  }
   113вҶ’};
   114вҶ’

