     1вҶ’/**
     2вҶ’ * GestureController - MediaPipe HandLandmarker integration with
     3вҶ’ * ONNX-based MLP gesture classification.
     4вҶ’ *
     5вҶ’ * Gestures detected (via trained MLP model):
     6вҶ’ *   "pinch"     - Thumb tip close to index tip
     7вҶ’ *   "fist"      - All fingers curled
     8вҶ’ *   "open_hand" - All fingers extended
     9вҶ’ *   "frame"     - Two hands forming a rectangle (bypass: both hands detected)
    10вҶ’ *   "none"      - No hand or ambiguous pose
    11вҶ’ */
    12вҶ’class GestureController {
    13вҶ’  // Label order matches sklearn LabelEncoder.fit() alphabetical sorting
    14вҶ’  static GESTURE_LABELS = ['fist', 'frame', 'none', 'open_hand', 'pinch'];
    15вҶ’
    16вҶ’  /**
    17вҶ’   * @param {HTMLVideoElement} videoElement
    18вҶ’   * @param {function} onGestureChange - Called when gesture changes: (gesture, confidence, handPos)
    19вҶ’   */
    20вҶ’  constructor(videoElement, onGestureChange) {
    21вҶ’    this.video = videoElement;
    22вҶ’    this.onGestureChange = onGestureChange;
    23вҶ’
    24вҶ’    this.handLandmarker = null;
    25вҶ’    this.camera = null;
    26вҶ’    this.running = false;
    27вҶ’
    28вҶ’    // ONNX inference session
    29вҶ’    this.session = null;
    30вҶ’    this._isInferring = false;
    31вҶ’    this._lastPrediction = { gesture: 'none', confidence: 0 };
    32вҶ’
    33вҶ’    // Current state
    34вҶ’    this._gesture = 'none';
    35вҶ’    this._confidence = 0;
    36вҶ’    this._handPosition = null; // { x, y } normalized 0-1
    37вҶ’    this._landmarks = null;
    38вҶ’
    39вҶ’    // Debounce: require N consecutive frames of same gesture
    40вҶ’    this._gestureBuffer = [];
    41вҶ’    this._bufferSize = 3;
    42вҶ’
    43вҶ’    // Confidence threshold
    44вҶ’    this._confidenceThreshold = 0.7;
    45вҶ’
    46вҶ’    // Canvas for skeleton overlay
    47вҶ’    this.overlayCanvas = null;
    48вҶ’    this.overlayCtx = null;
    49вҶ’
    50вҶ’    // Animation frame
    51вҶ’    this._animFrameId = null;
    52вҶ’  }
    53вҶ’
    54вҶ’  /**
    55вҶ’   * Initialize detector only (MediaPipe + ONNX) without starting camera or loop.
    56вҶ’   * Use this when you manage the camera and render loop externally.
    57вҶ’   * After calling this, use detectRaw(video) per frame.
    58вҶ’   * @returns {Promise<void>}
    59вҶ’   */
    60вҶ’  async initDetector() {
    61вҶ’    const vision = await this._loadMediaPipe();
    62вҶ’    const { HandLandmarker, FilesetResolver } = vision;
    63вҶ’
    64вҶ’    const wasmFileset = await FilesetResolver.forVisionTasks(
    65вҶ’      'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@latest/wasm'
    66вҶ’    );
    67вҶ’
    68вҶ’    this.handLandmarker = await HandLandmarker.createFromOptions(wasmFileset, {
    69вҶ’      baseOptions: {
    70вҶ’        modelAssetPath:
    71вҶ’          'https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/latest/hand_landmarker.task',
    72вҶ’        delegate: 'GPU',
    73вҶ’      },
    74вҶ’      runningMode: 'VIDEO',
    75вҶ’      numHands: 2,
    76вҶ’      minHandDetectionConfidence: 0.5,
    77вҶ’      minHandPresenceConfidence: 0.5,
    78вҶ’      minTrackingConfidence: 0.5,
    79вҶ’    });
    80вҶ’
    81вҶ’    await this._initONNXSession();
    82вҶ’  }
    83вҶ’
    84вҶ’  /**
    85вҶ’   * Detect hands in a video frame. Returns raw MediaPipe results.
    86вҶ’   * Call this per-frame from your own render loop.
    87вҶ’   * @param {HTMLVideoElement} video
    88вҶ’   * @returns {object|null} MediaPipe detection results with .landmarks array
    89вҶ’   */
    90вҶ’  detectRaw(video) {
    91вҶ’    if (!this.handLandmarker || video.readyState < 2) return null;
    92вҶ’    return this.handLandmarker.detectForVideo(video, performance.now());
    93вҶ’  }
    94вҶ’
    95вҶ’  /**
    96вҶ’   * Classify a single hand's landmarks using ONNX (or heuristic fallback).
    97вҶ’   * @param {Array} landmarks - 21 MediaPipe hand landmarks
    98вҶ’   * @returns {Promise<{gesture: string, confidence: number}>}
    99вҶ’   */
   100вҶ’  async classifyLandmarksAsync(landmarks) {
   101вҶ’    if (this.session && !this._isInferring) {
   102вҶ’      this._isInferring = true;
   103вҶ’      try {
   104вҶ’        await this._runInference(landmarks);
   105вҶ’      } finally {
   106вҶ’        this._isInferring = false;
   107вҶ’      }
   108вҶ’      return { ...this._lastPrediction };
   109вҶ’    }
   110вҶ’    // Fallback to heuristic
   111вҶ’    return this._classifyGesture(landmarks);
   112вҶ’  }
   113вҶ’
   114вҶ’  /**
   115вҶ’   * Initialize MediaPipe, ONNX session, and start processing.
   116вҶ’   * @returns {Promise<void>}
   117вҶ’   */
   118вҶ’  async init() {
   119вҶ’    // Import MediaPipe vision module from CDN
   120вҶ’    const vision = await this._loadMediaPipe();
   121вҶ’
   122вҶ’    const { HandLandmarker, FilesetResolver } = vision;
   123вҶ’
   124вҶ’    const wasmFileset = await FilesetResolver.forVisionTasks(
   125вҶ’      'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@latest/wasm'
   126вҶ’    );
   127вҶ’
   128вҶ’    this.handLandmarker = await HandLandmarker.createFromOptions(wasmFileset, {
   129вҶ’      baseOptions: {
   130вҶ’        modelAssetPath:
   131вҶ’          'https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/latest/hand_landmarker.task',
   132вҶ’        delegate: 'GPU',
   133вҶ’      },
   134вҶ’      runningMode: 'VIDEO',
   135вҶ’      numHands: 2,
   136вҶ’      minHandDetectionConfidence: 0.5,
   137вҶ’      minHandPresenceConfidence: 0.5,
   138вҶ’      minTrackingConfidence: 0.5,
   139вҶ’    });
   140вҶ’
   141вҶ’    // Initialize ONNX inference session
   142вҶ’    await this._initONNXSession();
   143вҶ’
   144вҶ’    // Start camera
   145вҶ’    await this._startCamera();
   146вҶ’    this.running = true;
   147вҶ’    this._processLoop();
   148вҶ’  }
   149вҶ’
   150вҶ’  /** Initialize ONNX Runtime inference session. */
   151вҶ’  async _initONNXSession() {
   152вҶ’    try {
   153вҶ’      this.session = await ort.InferenceSession.create('./mlp_model.onnx', {
   154вҶ’        executionProviders: ['wasm'],
   155вҶ’      });
   156вҶ’      console.log('ONNX session initialized.');
   157вҶ’    } catch (e) {
   158вҶ’      console.warn('ONNX session failed to load, falling back to heuristic:', e);
   159вҶ’      this.session = null;
   160вҶ’    }
   161вҶ’  }
   162вҶ’
   163вҶ’  /** Dynamically import the MediaPipe vision module. */
   164вҶ’  async _loadMediaPipe() {
   165вҶ’    // Use dynamic import from CDN
   166вҶ’    const module = await import(
   167вҶ’      'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@latest'
   168вҶ’    );
   169вҶ’    return module;
   170вҶ’  }
   171вҶ’
   172вҶ’  /** Start webcam stream. */
   173вҶ’  async _startCamera() {
   174вҶ’    const stream = await navigator.mediaDevices.getUserMedia({
   175вҶ’      video: { width: 320, height: 240, facingMode: 'user' },
   176вҶ’    });
   177вҶ’    this.video.srcObject = stream;
   178вҶ’    await new Promise((resolve) => {
   179вҶ’      this.video.onloadedmetadata = () => {
   180вҶ’        this.video.play();
   181вҶ’        resolve();
   182вҶ’      };
   183вҶ’    });
   184вҶ’  }
   185вҶ’
   186вҶ’  /** Set up the skeleton overlay canvas. */
   187вҶ’  setOverlayCanvas(canvas) {
   188вҶ’    this.overlayCanvas = canvas;
   189вҶ’    this.overlayCtx = canvas.getContext('2d');
   190вҶ’  }
   191вҶ’
   192вҶ’  /** Continuous processing loop. */
   193вҶ’  _processLoop() {
   194вҶ’    if (!this.running) return;
   195вҶ’
   196вҶ’    if (this.video.readyState >= 2) {
   197вҶ’      const timestamp = performance.now();
   198вҶ’      const results = this.handLandmarker.detectForVideo(this.video, timestamp);
   199вҶ’      this._processResults(results);
   200вҶ’    }
   201вҶ’
   202вҶ’    this._animFrameId = requestAnimationFrame(() => this._processLoop());
   203вҶ’  }
   204вҶ’
   205вҶ’  /**
   206вҶ’   * Process hand detection results.
   207вҶ’   * Uses ONNX inference when available, falls back to heuristic.
   208вҶ’   * @param {object} results - MediaPipe HandLandmarker results
   209вҶ’   */
   210вҶ’  _processResults(results) {
   211вҶ’    if (!results.landmarks || results.landmarks.length === 0) {
   212вҶ’      this._updateGesture('none', 0, null);
   213вҶ’      this._landmarks = null;
   214вҶ’      this._drawOverlay(null);
   215вҶ’      return;
   216вҶ’    }
   217вҶ’
   218вҶ’    const landmarks = results.landmarks[0]; // Primary hand
   219вҶ’    this._landmarks = results.landmarks;
   220вҶ’
   221вҶ’    // Calculate hand position (palm center = landmark 9, middle finger MCP)
   222вҶ’    const palm = landmarks[9];
   223вҶ’    // Mirror x since webcam is mirrored
   224вҶ’    this._handPosition = { x: 1 - palm.x, y: palm.y };
   225вҶ’
   226вҶ’    // Two-hand bypass: frame gesture
   227вҶ’    if (results.landmarks.length >= 2) {
   228вҶ’      this._updateGesture('frame', 0.9, this._handPosition);
   229вҶ’      this._drawOverlay(results.landmarks);
   230вҶ’      return;
   231вҶ’    }
   232вҶ’
   233вҶ’    // Single hand: run ONNX inference (async, non-blocking)
   234вҶ’    if (this.session && !this._isInferring) {
   235вҶ’      this._isInferring = true;
   236вҶ’      this._runInference(landmarks).finally(() => {
   237вҶ’        this._isInferring = false;
   238вҶ’      });
   239вҶ’    } else if (!this.session) {
   240вҶ’      // Fallback to heuristic when ONNX is unavailable
   241вҶ’      const heuristic = this._classifyGesture(landmarks);
   242вҶ’      this._lastPrediction = heuristic;
   243вҶ’    }
   244вҶ’
   245вҶ’    // Use latest prediction (may be from previous frame if currently inferring)
   246вҶ’    this._updateGesture(
   247вҶ’      this._lastPrediction.gesture,
   248вҶ’      this._lastPrediction.confidence,
   249вҶ’      this._handPosition
   250вҶ’    );
   251вҶ’
   252вҶ’    // Draw skeleton overlay
   253вҶ’    this._drawOverlay(results.landmarks);
   254вҶ’  }
   255вҶ’
   256вҶ’  /**
   257вҶ’   * Run async ONNX inference on landmarks.
   258вҶ’   * @param {Array} landmarks - 21 MediaPipe hand landmarks
   259вҶ’   */
   260вҶ’  async _runInference(landmarks) {
   261вҶ’    try {
   262вҶ’      const inputData = this._preprocessLandmarks(landmarks);
   263вҶ’      if (!inputData) return;
   264вҶ’
   265вҶ’      const tensor = new ort.Tensor('float32', inputData, [1, 60]);
   266вҶ’      const results = await this.session.run({ input: tensor });
   267вҶ’      const probabilities = results.output.data;
   268вҶ’
   269вҶ’      // Find class with highest probability
   270вҶ’      let maxProb = -1;
   271вҶ’      let bestIdx = -1;
   272вҶ’      for (let i = 0; i < probabilities.length; i++) {
   273вҶ’        if (probabilities[i] > maxProb) {
   274вҶ’          maxProb = probabilities[i];
   275вҶ’          bestIdx = i;
   276вҶ’        }
   277вҶ’      }
   278вҶ’
   279вҶ’      this._lastPrediction = {
   280вҶ’        gesture: GestureController.GESTURE_LABELS[bestIdx],
   281вҶ’        confidence: maxProb,
   282вҶ’      };
   283вҶ’    } catch (error) {
   284вҶ’      console.error('Inference error:', error);
   285вҶ’    }
   286вҶ’  }
   287вҶ’
   288вҶ’  /**
   289вҶ’   * Preprocess 21 MediaPipe landmarks to match the Python training pipeline.
   290вҶ’   *
   291вҶ’   * Steps:
   292вҶ’   *   1. Translate all landmarks relative to the wrist (landmark 0).
   293вҶ’   *   2. Scale by the Euclidean distance from wrist to middle finger MCP (landmark 9).
   294вҶ’   *   3. Drop the wrist landmark (now all zeros).
   295вҶ’   *   4. Flatten to a 60-element Float32Array (20 landmarks x 3 coords).
   296вҶ’   *
   297вҶ’   * @param {Array} landmarks - Array of 21 {x, y, z} landmark objects
   298вҶ’   * @returns {Float32Array|null} - 60-dim preprocessed vector, or null if invalid
   299вҶ’   */
   300вҶ’  _preprocessLandmarks(landmarks) {
   301вҶ’    if (!landmarks || landmarks.length !== 21) return null;
   302вҶ’
   303вҶ’    const wrist = landmarks[0];
   304вҶ’    const middleMCP = landmarks[9];
   305вҶ’
   306вҶ’    // Distance from wrist to middle MCP (scaling factor)
   307вҶ’    const dx = middleMCP.x - wrist.x;
   308вҶ’    const dy = middleMCP.y - wrist.y;
   309вҶ’    const dz = middleMCP.z - wrist.z;
   310вҶ’    const scale = Math.sqrt(dx * dx + dy * dy + dz * dz) || 1.0;
   311вҶ’
   312вҶ’    const out = new Float32Array(60);
   313вҶ’    let idx = 0;
   314вҶ’
   315вҶ’    // Start from landmark 1 (drop wrist)
   316вҶ’    for (let i = 1; i < landmarks.length; i++) {
   317вҶ’      const lm = landmarks[i];
   318вҶ’      out[idx++] = (lm.x - wrist.x) / scale;
   319вҶ’      out[idx++] = (lm.y - wrist.y) / scale;
   320вҶ’      out[idx++] = (lm.z - wrist.z) / scale;
   321вҶ’    }
   322вҶ’
   323вҶ’    return out;
   324вҶ’  }
