   326вҶ’  /**
   327вҶ’   * Heuristic gesture classifier (fallback when ONNX is unavailable).
   328вҶ’   * Uses distances between finger tips and palm base.
   329вҶ’   *
   330вҶ’   * Landmark indices (per hand):
   331вҶ’   *   0: wrist
   332вҶ’   *   1-4: thumb (CMC, MCP, IP, TIP)
   333вҶ’   *   5-8: index (MCP, PIP, DIP, TIP)
   334вҶ’   *   9-12: middle (MCP, PIP, DIP, TIP)
   335вҶ’   *   13-16: ring (MCP, PIP, DIP, TIP)
   336вҶ’   *   17-20: pinky (MCP, PIP, DIP, TIP)
   337вҶ’   */
   338вҶ’  _classifyGesture(lm) {
   339вҶ’    const thumbTip = lm[4];
   340вҶ’    const indexTip = lm[8];
   341вҶ’    const middleTip = lm[12];
   342вҶ’    const ringTip = lm[16];
   343вҶ’    const pinkyTip = lm[20];
   344вҶ’
   345вҶ’    const indexMCP = lm[5];
   346вҶ’    const middleMCP = lm[9];
   347вҶ’    const ringMCP = lm[13];
   348вҶ’    const pinkyMCP = lm[17];
   349вҶ’
   350вҶ’    const wrist = lm[0];
   351вҶ’
   352вҶ’    // Finger extension: tip is farther from wrist than MCP
   353вҶ’    const fingerExtended = (tip, mcp) => {
   354вҶ’      const tipDist = this._dist3D(tip, wrist);
   355вҶ’      const mcpDist = this._dist3D(mcp, wrist);
   356вҶ’      return tipDist > mcpDist * 1.1;
   357вҶ’    };
   358вҶ’
   359вҶ’    const indexExt = fingerExtended(indexTip, indexMCP);
   360вҶ’    const middleExt = fingerExtended(middleTip, middleMCP);
   361вҶ’    const ringExt = fingerExtended(ringTip, ringMCP);
   362вҶ’    const pinkyExt = fingerExtended(pinkyTip, pinkyMCP);
   363вҶ’
   364вҶ’    // Thumb extension (compare to index MCP)
   365вҶ’    const thumbExt = this._dist3D(thumbTip, wrist) > this._dist3D(lm[2], wrist) * 1.1;
   366вҶ’
   367вҶ’    // Pinch: thumb tip close to index tip
   368вҶ’    const pinchDist = this._dist3D(thumbTip, indexTip);
   369вҶ’    if (pinchDist < 0.06) {
   370вҶ’      return { gesture: 'pinch', confidence: Math.min(1, 1 - pinchDist / 0.06) };
   371вҶ’    }
   372вҶ’
   373вҶ’    // Count extended fingers
   374вҶ’    const extCount = [indexExt, middleExt, ringExt, pinkyExt].filter(Boolean).length;
   375вҶ’
   376вҶ’    // Fist: no fingers extended (and thumb not extended)
   377вҶ’    if (extCount === 0 && !thumbExt) {
   378вҶ’      return { gesture: 'fist', confidence: 0.85 };
   379вҶ’    }
   380вҶ’
   381вҶ’    // Open hand: all fingers extended
   382вҶ’    if (extCount >= 3 && thumbExt) {
   383вҶ’      return { gesture: 'open_hand', confidence: 0.8 + extCount * 0.04 };
   384вҶ’    }
   385вҶ’
   386вҶ’    // Default: none with low confidence
   387вҶ’    return { gesture: 'none', confidence: 0.3 };
   388вҶ’  }
