   390вҶ’  /** 3D Euclidean distance between two landmarks. */
   391вҶ’  _dist3D(a, b) {
   392вҶ’    return Math.sqrt((a.x - b.x) ** 2 + (a.y - b.y) ** 2 + (a.z - b.z) ** 2);
