   420вҶ’      }
   421вҶ’    } else {
   422вҶ’      this._confidence = confidence;
   423вҶ’    }
   424вҶ’
   425вҶ’    // Always update hand position callback for smooth tracking
   426вҶ’    if (handPos && this.onGestureChange && this._gesture !== 'none') {
   427вҶ’      this.onGestureChange(this._gesture, this._confidence, handPos);
   428вҶ’    }
   429вҶ’  }
