   431вҶ’  /** Draw hand skeleton on overlay canvas. */
   432вҶ’  _drawOverlay(allLandmarks) {
   433вҶ’    if (!this.overlayCanvas || !this.overlayCtx) return;
   434вҶ’    const ctx = this.overlayCtx;
   435вҶ’    const w = this.overlayCanvas.width;
   436вҶ’    const h = this.overlayCanvas.height;
   437вҶ’
   438вҶ’    ctx.clearRect(0, 0, w, h);
   439вҶ’
   440вҶ’    if (!allLandmarks) return;
   441вҶ’
   442вҶ’    // Connection pairs for hand skeleton
   443вҶ’    const connections = [
   444вҶ’      [0, 1], [1, 2], [2, 3], [3, 4],       // thumb
   445вҶ’      [0, 5], [5, 6], [6, 7], [7, 8],       // index
   446вҶ’      [0, 9], [9, 10], [10, 11], [11, 12],  // middle
   447вҶ’      [0, 13], [13, 14], [14, 15], [15, 16],// ring
   448вҶ’      [0, 17], [17, 18], [18, 19], [19, 20],// pinky
   449вҶ’      [5, 9], [9, 13], [13, 17],            // palm
   450вҶ’    ];
   451вҶ’
   452вҶ’    for (const landmarks of allLandmarks) {
   453вҶ’      // Draw connections
   454вҶ’      ctx.strokeStyle = 'rgba(100, 180, 255, 0.7)';
   455вҶ’      ctx.lineWidth = 2;
   456вҶ’      for (const [a, b] of connections) {
   457вҶ’        ctx.beginPath();
   458вҶ’        // Mirror x for display
   459вҶ’        ctx.moveTo((1 - landmarks[a].x) * w, landmarks[a].y * h);
   460вҶ’        ctx.lineTo((1 - landmarks[b].x) * w, landmarks[b].y * h);
   461вҶ’        ctx.stroke();
   462вҶ’      }
   463вҶ’
   464вҶ’      // Draw landmarks
   465вҶ’      for (let i = 0; i < landmarks.length; i++) {
   466вҶ’        const lm = landmarks[i];
   467вҶ’        ctx.beginPath();
   468вҶ’        ctx.arc((1 - lm.x) * w, lm.y * h, 3, 0, Math.PI * 2);
   469вҶ’        ctx.fillStyle =
   470вҶ’          i === 4 || i === 8 ? 'rgba(255, 100, 100, 0.9)' : 'rgba(255, 255, 255, 0.8)';
   471вҶ’        ctx.fill();
   472вҶ’      }
   473вҶ’    }
   474вҶ’  }
