   351вҶ’  // ---------------------------------------------------------------
   352вҶ’  // Hand analysis helpers
   353вҶ’  // ---------------------------------------------------------------
   354вҶ’  function pinchDistance(hand) {
   355вҶ’    const thumb = hand[4];
   356вҶ’    const index = hand[8];
   357вҶ’    return Math.hypot(thumb.x - index.x, thumb.y - index.y);
   358вҶ’  }
   359вҶ’
   360вҶ’  function isPinching(hand) {
   361вҶ’    return pinchDistance(hand) < PINCH_THRESHOLD;
   362вҶ’  }
   363вҶ’
   364вҶ’  function isFrameGesture(hand) {
   365вҶ’    // Thumb and index spread apart
   366вҶ’    return Math.hypot(hand[8].x - hand[4].x, hand[8].y - hand[4].y) > FRAME_THRESHOLD;
   367вҶ’  }
   368вҶ’
   369вҶ’  function isFist(hand) {
   370вҶ’    const wrist = hand[0];
   371вҶ’    const tips = [8, 12, 16, 20];
   372вҶ’    const pips = [6, 10, 14, 18];
   373вҶ’    let closed = 0;
   374вҶ’    for (let i = 0; i < tips.length; i++) {
   375вҶ’      const tip = hand[tips[i]];
   376вҶ’      const pip = hand[pips[i]];
   377вҶ’      const dTip = Math.hypot(tip.x - wrist.x, tip.y - wrist.y);
   378вҶ’      const dPip = Math.hypot(pip.x - wrist.x, pip.y - wrist.y);
   379вҶ’      if (dTip < dPip) closed++;
   380вҶ’    }
   381вҶ’    return closed === 4;
   382вҶ’  }
