   384вҶ’  // ---------------------------------------------------------------
   385вҶ’  // Skeleton drawing
   386вҶ’  // ---------------------------------------------------------------
   387вҶ’  function drawSkeleton(allLandmarks, width, height) {
   388вҶ’    for (const landmarks of allLandmarks) {
   389вҶ’      // Draw connections
   390вҶ’      ctx.strokeStyle = '#ffffff';
   391вҶ’      ctx.lineWidth = 3;
   392вҶ’      for (const [a, b] of HAND_CONNECTIONS) {
   393вҶ’        ctx.beginPath();
   394вҶ’        ctx.moveTo((1 - landmarks[a].x) * width, landmarks[a].y * height);
   395вҶ’        ctx.lineTo((1 - landmarks[b].x) * width, landmarks[b].y * height);
   396вҶ’        ctx.stroke();
   397вҶ’      }
   398вҶ’      // Draw joints
   399вҶ’      for (let i = 0; i < landmarks.length; i++) {
   400вҶ’        const lm = landmarks[i];
   401вҶ’        ctx.beginPath();
   402вҶ’        ctx.arc((1 - lm.x) * width, lm.y * height, 3, 0, Math.PI * 2);
   403вҶ’        ctx.fillStyle = '#ffffff';
   404вҶ’        ctx.fill();
   405вҶ’      }
   406вҶ’    }
   407вҶ’  }
   408вҶ’
   409вҶ’  // ---------------------------------------------------------------
   410вҶ’  // Main render loop
   411вҶ’  // ---------------------------------------------------------------
   412вҶ’  function renderLoop() {
   413вҶ’    if (!canvas || !cameraReady) {
   414вҶ’      requestAnimationFrame(renderLoop);
   415вҶ’      return;
   416вҶ’    }
   417вҶ’
   418вҶ’    if (video.readyState < 2) {
   419вҶ’      requestAnimationFrame(renderLoop);
   420вҶ’      return;
   421вҶ’    }
   422вҶ’
   423вҶ’    // Match canvas to video size
   424вҶ’    if (canvas.width !== video.videoWidth || canvas.height !== video.videoHeight) {
   425вҶ’      canvas.width = video.videoWidth;
   426вҶ’      canvas.height = video.videoHeight;
   427вҶ’    }
   428вҶ’
   429вҶ’    const width = canvas.width;
   430вҶ’    const height = canvas.height;
   431вҶ’    ctx.clearRect(0, 0, width, height);
   432вҶ’
   433вҶ’    // Detect hands
   434вҶ’    let results = null;
   435вҶ’    if (gestureCtrl && modelLoaded) {
   436вҶ’      results = gestureCtrl.detectRaw(video);
   437вҶ’    }
   438вҶ’
   439вҶ’    // ---- SCANNING / LEADERBOARD ----
   440вҶ’    if (gameState === 'SCANNING' || gameState === 'LEADERBOARD') {
   441вҶ’      // Draw mirrored camera
   442вҶ’      ctx.save();
   443вҶ’      ctx.translate(width, 0);
   444вҶ’      ctx.scale(-1, 1);
   445вҶ’      ctx.drawImage(video, 0, 0, width, height);
   446вҶ’      ctx.restore();
   447вҶ’
   448вҶ’      if (gameState === 'SCANNING') {
   449вҶ’        handleScanning(results, width, height);
   450вҶ’      }
   451вҶ’    }
   452вҶ’
   453вҶ’    // ---- PLAYING / SOLVED ----
   454вҶ’    else if ((gameState === 'PLAYING' || gameState === 'SOLVED') && puzzleImageCanvas && boardCoords) {
   455вҶ’      // Draw mirrored camera background
   456вҶ’      ctx.save();
   457вҶ’      ctx.translate(width, 0);
   458вҶ’      ctx.scale(-1, 1);
   459вҶ’      ctx.drawImage(video, 0, 0, width, height);
   460вҶ’      ctx.restore();
   461вҶ’
   462вҶ’      handlePlaying(results, width, height);
   463вҶ’    }
   464вҶ’
   465вҶ’    // Draw skeleton (except during leaderboard)
   466вҶ’    if (results && results.landmarks && results.landmarks.length > 0 && gameState !== 'LEADERBOARD') {
   467вҶ’      drawSkeleton(results.landmarks, width, height);
   468вҶ’    }
   469вҶ’
   470вҶ’    requestAnimationFrame(renderLoop);
   471вҶ’  }
   472вҶ’
   473вҶ’  // ---------------------------------------------------------------
   474вҶ’  // SCANNING handler
   475вҶ’  // ---------------------------------------------------------------
   476вҶ’  function handleScanning(results, width, height) {
   477вҶ’    if (!results || !results.landmarks || results.landmarks.length < 2) {
   478вҶ’      lastFrameCoords = null; // Clear stale frame when fewer than 2 hands
   479вҶ’      return;
   480вҶ’    }
   481вҶ’
   482вҶ’    const h1 = results.landmarks[0];
   483вҶ’    const h2 = results.landmarks[1];
   484вҶ’
   485вҶ’    const d1 = Math.hypot(h1[8].x - h1[4].x, h1[8].y - h1[4].y);
   486вҶ’    const d2 = Math.hypot(h2[8].x - h2[4].x, h2[8].y - h2[4].y);
   487вҶ’
   488вҶ’    let validFrame = false;
   489вҶ’
   490вҶ’    // Frame detection: both hands have spread thumb-index
   491вҶ’    if (d1 > FRAME_THRESHOLD && d2 > FRAME_THRESHOLD) {
   492вҶ’      const allX = [h1[8].x, h1[4].x, h2[8].x, h2[4].x];
   493вҶ’      const allY = [h1[8].y, h1[4].y, h2[8].y, h2[4].y];
   494вҶ’      lastFrameCoords = {
   495вҶ’        minX: Math.min(...allX),
   496вҶ’        maxX: Math.max(...allX),
   497вҶ’        minY: Math.min(...allY),
   498вҶ’        maxY: Math.max(...allY),
   499вҶ’      };
   500вҶ’      validFrame = true;
   501вҶ’    }
   502вҶ’
   503вҶ’    // Pinch capture: both hands pinch while frame was established
   504вҶ’    if (d1 < PINCH_THRESHOLD && d2 < PINCH_THRESHOLD && lastFrameCoords) {
   505вҶ’      const now = Date.now();
   506вҶ’      if (now - lastPinchTime > 1000) {
   507вҶ’        lastPinchTime = now;
   508вҶ’        captureAndStartGame(width, height);
   509вҶ’      }
   510вҶ’    }
   511вҶ’
   512вҶ’    // Draw frame overlay
   513вҶ’    if (lastFrameCoords && validFrame) {
   514вҶ’      const c = lastFrameCoords;
   515вҶ’      const sx = (1 - c.maxX) * width;
   516вҶ’      const ex = (1 - c.minX) * width;
   517вҶ’      const sy = c.minY * height;
   518вҶ’      const ey = c.maxY * height;
   519вҶ’
   520вҶ’      ctx.strokeStyle = '#ccff00';
   521вҶ’      ctx.lineWidth = 4;
   522вҶ’      ctx.strokeRect(sx, sy, ex - sx, ey - sy);
   523вҶ’
   524вҶ’      ctx.fillStyle = '#ffffff';
   525вҶ’      ctx.font = 'bold 14px monospace';
   526вҶ’      ctx.fillText('PINCH TO CAPTURE', sx, sy - 8);
   527вҶ’    }
   528вҶ’  }
   529вҶ’
   530вҶ’  // ---------------------------------------------------------------
   531вҶ’  // Capture framed area and start game
   532вҶ’  // ---------------------------------------------------------------
   533вҶ’  function captureAndStartGame(width, height) {
   534вҶ’    const c = lastFrameCoords;
   535вҶ’    const fullFrame = captureFrame(width, height);
   536вҶ’
   537вҶ’    // Calculate crop area from frame coordinates
   538вҶ’    const sx = (1 - c.maxX) * width;
   539вҶ’    const sy = c.minY * height;
   540вҶ’    const sw = ((1 - c.minX) * width) - sx;
   541вҶ’    const sh = (c.maxY * height) - sy;
   542вҶ’
   543вҶ’    if (sw <= 0 || sh <= 0) return;
   544вҶ’
   545вҶ’    // Create cropped image canvas
   546вҶ’    const cropCanvas = document.createElement('canvas');
   547вҶ’    cropCanvas.width = sw * 2;
   548вҶ’    cropCanvas.height = sh * 2;
   549вҶ’    const cropCtx = cropCanvas.getContext('2d');
   550вҶ’    if (cropCtx) {
   551вҶ’      cropCtx.drawImage(fullFrame, sx, sy, sw, sh, 0, 0, cropCanvas.width, cropCanvas.height);
   552вҶ’    }
   553вҶ’
   554вҶ’    puzzleImageCanvas = cropCanvas;
   555вҶ’    tiles = SwapPuzzle.generate(COLS, ROWS);
   556вҶ’    boardCoords = { ...c };
   557вҶ’    startPlaying();
   558вҶ’  }
   559вҶ’
   560вҶ’  // ---------------------------------------------------------------
   561вҶ’  // PLAYING handler
   562вҶ’  // ---------------------------------------------------------------
   563вҶ’  function handlePlaying(results, width, height) {
   564вҶ’    const c = boardCoords;
   565вҶ’    const boardSX = (1 - c.maxX) * width;
   566вҶ’    const boardSY = c.minY * height;
   567вҶ’    const boardW = ((1 - c.minX) * width) - boardSX;
   568вҶ’    const boardH = (c.maxY * height) - boardSY;
   569вҶ’
   570вҶ’    let hoverIndex = null;
   571вҶ’    let pinching = false;
   572вҶ’    let interactingHand = null;
   573вҶ’
   574вҶ’    // Process hand input
   575вҶ’    if (results && results.landmarks && results.landmarks.length > 0) {
   576вҶ’      const hand = results.landmarks[0];
   577вҶ’      interactingHand = hand;
   578вҶ’
   579вҶ’      const indexTip = hand[8];
   580вҶ’      const thumbTip = hand[4];
   581вҶ’
   582вҶ’      // Raw pointer position (mirrored)
   583вҶ’      const rawX = (1 - (indexTip.x + thumbTip.x) / 2) * width;
   584вҶ’      const rawY = ((indexTip.y + thumbTip.y) / 2) * height;
   585вҶ’
   586вҶ’      // Pinch state
   587вҶ’      const dist = Math.hypot(indexTip.x - thumbTip.x, indexTip.y - thumbTip.y);
   588вҶ’      pinching = dist < PINCH_THRESHOLD;
   589вҶ’
   590вҶ’      // Smooth cursor (lerp based on distance)
   591вҶ’      const distMove = Math.hypot(rawX - smoothCursor.x, rawY - smoothCursor.y);
   592вҶ’      const alpha = distMove > 100 ? 1.0 : 0.4;
   593вҶ’      smoothCursor.x = smoothCursor.x * (1 - alpha) + rawX * alpha;
   594вҶ’      smoothCursor.y = smoothCursor.y * (1 - alpha) + rawY * alpha;
   595вҶ’    }
   596вҶ’
   597вҶ’    const cursorX = smoothCursor.x;
   598вҶ’    const cursorY = smoothCursor.y;
   599вҶ’
   600вҶ’    // Calculate tile under cursor
   601вҶ’    const relX = cursorX - boardSX;
   602вҶ’    const relY = cursorY - boardSY;
   603вҶ’    if (relX >= 0 && relX <= boardW && relY >= 0 && relY <= boardH) {
   604вҶ’      const col = Math.floor(relX / (boardW / COLS));
   605вҶ’      const row = Math.floor(relY / (boardH / ROWS));
   606вҶ’      if (col >= 0 && col < COLS && row >= 0 && row < ROWS) {
   607вҶ’        hoverIndex = row * COLS + col;
   608вҶ’      }
   609вҶ’    }
   610вҶ’
   611вҶ’    // Drag & drop logic (only during PLAYING)
   612вҶ’    if (gameState === 'PLAYING') {
   613вҶ’      if (pinching) {
   614вҶ’        if (!isDragging && hoverIndex !== null) {
   615вҶ’          // Start drag
   616вҶ’          isDragging = true;
   617вҶ’          dragTileIndex = hoverIndex;
   618вҶ’        }
   619вҶ’      } else {
   620вҶ’        if (isDragging) {
   621вҶ’          // Drop - swap tiles
   622вҶ’          if (dragTileIndex !== null && hoverIndex !== null && dragTileIndex !== hoverIndex) {
   623вҶ’            [tiles[dragTileIndex], tiles[hoverIndex]] = [tiles[hoverIndex], tiles[dragTileIndex]];
   624вҶ’            if (SwapPuzzle.isSolved(tiles)) {
   625вҶ’              onSolved();
   626вҶ’            }
   627вҶ’          }
   628вҶ’          isDragging = false;
   629вҶ’          dragTileIndex = null;
   630вҶ’        }
   631вҶ’      }
   632вҶ’    }
   633вҶ’
   634вҶ’    // Render puzzle
   635вҶ’    ctx.save();
   636вҶ’    ctx.translate(boardSX, boardSY);
   637вҶ’
   638вҶ’    SwapPuzzle.render(
   639вҶ’      ctx,
   640вҶ’      puzzleImageCanvas,
   641вҶ’      tiles,
   642вҶ’      COLS, ROWS,
   643вҶ’      boardW, boardH,
   644вҶ’      isDragging && dragTileIndex !== null ? { index: dragTileIndex, x: relX, y: relY } : null,
   645вҶ’      hoverIndex
   646вҶ’    );
   647вҶ’
   648вҶ’    // Board border
   649вҶ’    ctx.strokeStyle = '#ffffff';
   650вҶ’    ctx.lineWidth = 4;
   651вҶ’    ctx.strokeRect(0, 0, boardW, boardH);
   652вҶ’
   653вҶ’    ctx.restore();
   654вҶ’
   655вҶ’    // Draw cursor
   656вҶ’    if (results && results.landmarks && results.landmarks.length > 0) {
   657вҶ’      ctx.beginPath();
   658вҶ’      ctx.arc(cursorX, cursorY, 10, 0, Math.PI * 2);
   659вҶ’      if (isDragging) {
   660вҶ’        ctx.fillStyle = '#ccff00';
   661вҶ’        ctx.fill();
   662вҶ’      } else {
   663вҶ’        ctx.strokeStyle = '#ccff00';
   664вҶ’        ctx.lineWidth = 2;
   665вҶ’        ctx.stroke();
   666вҶ’      }
   667вҶ’    }
   668вҶ’
   669вҶ’    // Fist detection for reset
   670вҶ’    let fistDetected = false;
   671вҶ’    if (interactingHand && gameState === 'PLAYING') {
   672вҶ’      fistDetected = isFist(interactingHand);
   673вҶ’    }
   674вҶ’
   675вҶ’    if (fistDetected && gameState === 'PLAYING') {
   676вҶ’      if (!fistHoldStart) {
   677вҶ’        fistHoldStart = performance.now();
   678вҶ’      }
   679вҶ’      const elapsed = performance.now() - fistHoldStart;
   680вҶ’      const progress = Math.min(elapsed / RESET_DWELL_MS, 1);
   681вҶ’
   682вҶ’      // Draw reset progress
   683вҶ’      const cx = width / 2;
   684вҶ’      const cy = height / 2;
   685вҶ’
   686вҶ’      ctx.save();
   687вҶ’      ctx.beginPath();
   688вҶ’      ctx.arc(cx, cy, 50, 0, Math.PI * 2);
   689вҶ’      ctx.fillStyle = 'rgba(0, 0, 0, 0.6)';
   690вҶ’      ctx.fill();
   691вҶ’
   692вҶ’      ctx.beginPath();
   693вҶ’      ctx.arc(cx, cy, 50, -Math.PI / 2, -Math.PI / 2 + Math.PI * 2 * progress);
   694вҶ’      ctx.strokeStyle = '#ccff00';
   695вҶ’      ctx.lineWidth = 6;
   696вҶ’      ctx.lineCap = 'round';
   697вҶ’      ctx.stroke();
   698вҶ’
   699вҶ’      ctx.fillStyle = '#ffffff';
   700вҶ’      ctx.font = 'bold 14px monospace';
   701вҶ’      ctx.textAlign = 'center';
   702вҶ’      ctx.textBaseline = 'middle';
   703вҶ’      ctx.fillText('RESETTING', cx, cy - 5);
   704вҶ’      ctx.font = '10px monospace';
   705вҶ’      ctx.fillText('Hold Fist', cx, cy + 10);
   706вҶ’      ctx.restore();
   707вҶ’
   708вҶ’      if (elapsed > RESET_DWELL_MS) {
   709вҶ’        resetGame();
   710вҶ’      }
   711вҶ’    } else {
   712вҶ’      fistHoldStart = null;
   713вҶ’    }
   714вҶ’  }
