   746вҶ’  // Bootstrap
   747вҶ’  // ---------------------------------------------------------------
   748вҶ’  async function init() {
   749вҶ’    updateUI();
   750вҶ’
   751вҶ’    // Start camera first, then detection
   752вҶ’    await startCamera();
   753вҶ’    if (!cameraReady) return;
